    "dataSource": "File, WinEventLog:Microsoft-Windows-Backup, WinEventLog:Sysmon, auditd:CONFIG_CHANGE, auditd:SYSCALL, docker:daemon, esxi:hostd, esxi:shell, fs:fsusage, linux:Sysmon, macos:osquery, macos:unifiedlog"
